@namespace Lumeo

<div class="@ContainerClass" style="@ContainerStyle" role="img" aria-label="@(AriaLabel ?? $"QR code: {Value}")" @attributes="AdditionalAttributes">
    <svg viewBox="@ViewBox" xmlns="http://www.w3.org/2000/svg" style="display: block; width: 100%; height: 100%;" aria-hidden="true">
        <rect x="0" y="0" width="@_totalSize" height="@_totalSize" fill="@BackgroundColor" />
        @if (_darkModules is not null)
        {
            @foreach (var (x, y) in _darkModules)
            {
                <rect x="@x" y="@y" width="1" height="1" fill="@ForegroundColor" />
            }
        }
        @if (!string.IsNullOrEmpty(ImageSrc) && _moduleCount > 0)
        {
            @* ImageSize is documented in PIXELS of the rendered Size-px box,
               but the viewBox is in MODULE units (~21-77): using it raw made
               the default 40 cover 60-130% of the code — unscannable. Scale
               px → modules; invariant formatting (SVG rejects "13,8"). *@
            double imgUnits = Size > 0 ? (double)ImageSize / Size * _totalSize : 0;
            string imgDim = imgUnits.ToString("0.###", System.Globalization.CultureInfo.InvariantCulture);
            string imgPos = ((_totalSize - imgUnits) / 2).ToString("0.###", System.Globalization.CultureInfo.InvariantCulture);
            <image href="@ImageSrc" x="@imgPos" y="@imgPos" width="@imgDim" height="@imgDim"
                   preserveAspectRatio="xMidYMid meet" style="border-radius: 4px;" />
        }
    </svg>
</div>

@code {
    [Parameter] public string? Value { get; set; }
    [Parameter] public int Size { get; set; } = 200;
    [Parameter] public QRErrorLevel ErrorCorrectionLevel { get; set; } = QRErrorLevel.Medium;
    [Parameter] public string ForegroundColor { get; set; } = "currentColor";
    [Parameter] public string BackgroundColor { get; set; } = "transparent";
    [Parameter] public bool IncludeMargin { get; set; } = true;
    [Parameter] public string? ImageSrc { get; set; }
    [Parameter] public int ImageSize { get; set; } = 40;
    /// <summary>Override the accessible label announced for the QR code.
    /// Defaults to <c>"QR code: {Value}"</c>. Useful when the encoded
    /// payload is a long URL or technical string the user doesn't need
    /// read out — pass a human-friendly description instead.</summary>
    [Parameter] public string? AriaLabel { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private IReadOnlyList<(int x, int y)>? _darkModules;
    private int _moduleCount;
    private int _margin;
    private int _totalSize;

    private string ContainerClass => Cx.Merge("inline-block overflow-hidden rounded-xl", Class);
    private string ContainerStyle => $"width: {Size}px; height: {Size}px;";
    private string ViewBox => $"0 0 {_totalSize} {_totalSize}";

    protected override void OnParametersSet() => Rebuild();

    private void Rebuild()
    {
        if (string.IsNullOrEmpty(Value))
        {
            _darkModules = null;
            _moduleCount = 0;
            _margin = 0;
            _totalSize = 0;
            return;
        }

        try
        {
            var ecl = ErrorCorrectionLevel switch
            {
                QRErrorLevel.Low => QRCoder.QRCodeGenerator.ECCLevel.L,
                QRErrorLevel.Quartile => QRCoder.QRCodeGenerator.ECCLevel.Q,
                QRErrorLevel.High => QRCoder.QRCodeGenerator.ECCLevel.H,
                _ => QRCoder.QRCodeGenerator.ECCLevel.M,
            };

            using var gen = new QRCoder.QRCodeGenerator();
            using var data = gen.CreateQrCode(Value, ecl);
            var pixels = data.ModuleMatrix;
            _moduleCount = pixels.Count;
            _margin = IncludeMargin ? 4 : 0;
            _totalSize = _moduleCount + _margin * 2;

            var modules = new List<(int x, int y)>();
            for (int row = 0; row < _moduleCount; row++)
            for (int col = 0; col < _moduleCount; col++)
                if (pixels[row][col])
                    modules.Add((col + _margin, row + _margin));

            _darkModules = modules;
        }
        catch
        {
            _darkModules = null;
            _moduleCount = 0;
            _margin = 0;
            _totalSize = 0;
        }
    }

    public enum QRErrorLevel { Low, Medium, Quartile, High }
}
